public class Main {
    public static void main(String[] args) {
        StringBuilder sb = new StringBuilder();
        for (int i = 1; i <= 5; i++) {
            sb.append(i);
            if (i < 5) sb.append("-");
        }
        System.out.println(sb.toString());  // 1-2-3-4-5

        sb.reverse();
        System.out.println(sb.toString());  // 5-4-3-2-1

        System.out.println(sb.length());    // 9
    }
}

