public class Main {
    public static void main(String[] args) {
        String s = "  Hello World  ";
        String trimmed = s.trim();
        System.out.println(trimmed);               // Hello World
        System.out.println(s);                     // still "  Hello World  "

        String replaced = trimmed.replace("World", "Java");
        System.out.println(replaced);              // Hello Java
        System.out.println(trimmed);               // still Hello World

        System.out.println("".isEmpty());           // true
        System.out.println(" ".isEmpty());          // false
    }
}

